import{_ as r,C as i,c as s,o as p,ai as e,j as n,a as t,G as g}from"./chunks/framework.TS84ywiI.js";const y=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"Spring/Spring整体脉络/16张图解锁Spring的整体脉络.md","filePath":"Spring/Spring整体脉络/16张图解锁Spring的整体脉络.md"}'),l={name:"Spring/Spring整体脉络/16张图解锁Spring的整体脉络.md"};function c(h,a,m,d,u,B){const o=i("bean");return p(),s("div",null,[a[2]||(a[2]=e('<p>作者: <a href="https://github.com/Java4ye" target="_blank" rel="noreferrer">Java4ye</a></p><h3 id="概览" tabindex="-1">概览 <a class="header-anchor" href="#概览" aria-label="Permalink to &quot;概览&quot;">​</a></h3><p>本文将讲解 Spring 的原理，看看一个 Bean 是怎么被创建出来的，中间经历过那几道工序加工，它的生命周期是怎样的，以及有哪些扩展点，后置处理器可以使用，让你对 Spring 多一些了解！</p><h3 id="目录" tabindex="-1">目录 <a class="header-anchor" href="#目录" aria-label="Permalink to &quot;目录&quot;">​</a></h3><p>本文会先大概介绍下这些知识点 👇</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/spring/image-20211213224509864.png" alt="image-20211213224509864"></p><h3 id="印象中的-spring" tabindex="-1">印象中的 Spring <a class="header-anchor" href="#印象中的-spring" aria-label="Permalink to &quot;印象中的 Spring&quot;">​</a></h3><p>脑海中有这么一条公式：</p><p>👉 IOC = 工厂模式 + XML + 反射</p><p>👉 而 DI , AOP ， <strong>事务</strong> 等也都在 XML 中很直观的表现出来</p><p>虽然我们现在大部分用这个注解来代替，但是原理还是基本一样的 🐖</p><p>注解使用起来很方便，但是学习的话，还是建议先通过这个 XML ，毕竟结构性的文档，有层次感，可以留下更深的印象~ 😄</p><h3 id="小小-spring" tabindex="-1">小小 Spring <a class="header-anchor" href="#小小-spring" aria-label="Permalink to &quot;小小 Spring&quot;">​</a></h3><p>把 Spring 浓缩一下，就有了这么一点小东西 🐖</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/spring/image-20211213224920994.png" alt="image-20211213224920994"></p><p>想了下，我们用 Spring ，其中最主要的一点，就是用它来帮我们管理，创建这个 Bean 。</p><p>那么先从源头看起 —— Bean 从哪来 (＠_＠😉</p><h3 id="bean-解析流程" tabindex="-1">Bean 解析流程 <a class="header-anchor" href="#bean-解析流程" aria-label="Permalink to &quot;Bean 解析流程&quot;">​</a></h3><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/spring/image-20211213225044814.png" alt="image-20211213225044814"></p><p>如图所示，就是通过 <strong>解析器</strong>，对我们的 XML 文件或者注解进行解析，最后将这些信息封装在 BeanDefinition 类中，并通过 BeanDefinitionRegistry 接口将这些信息 <strong>注册</strong> 起来，放在 beanDefinitionMap 变量中, key : beanName , value ：BeanDefinition 。</p><p>简单看看 BeanDefinition 中的属性叭</p><h3 id="beandefinition" tabindex="-1">BeanDefinition <a class="header-anchor" href="#beandefinition" aria-label="Permalink to &quot;BeanDefinition&quot;">​</a></h3><ul><li><p>beanClass : bean 的类型 ，实例化时用的 🐖</p></li><li><p>scope : 作用范围有 singleton，prototype</p></li><li><p>isLazy : <strong>懒加载</strong> ，true 的话 会在 getBean 时生成，而且 scope 的 prototype 无效，false 在 Spring 启动过程中直接生成</p></li><li><p>initMethodName : 初始化方法，当然是初始化时调用 🐖</p></li><li><p>primary : 主要的，有多个 Bean 时使用它</p></li><li><p>dependsOn : 依赖的 Bean，必须等依赖 Bean 创建好才可以创建</p></li></ul>',23)),n("blockquote",null,[n("p",null,[a[0]||(a[0]=t("PS: @Component ，@Bean , ")),g(o),a[1]||(a[1]=t(" 都会被解析成 BeanDefinition"))])]),a[3]||(a[3]=e('<h3 id="反射" tabindex="-1">反射 <a class="header-anchor" href="#反射" aria-label="Permalink to &quot;反射&quot;">​</a></h3><p>有了原料后呢，咋们再来看看这个 <strong>工厂</strong> BeanFactory</p><p>先简单想一想这个工厂要怎么创建这个 Bean 呢？</p><p>没错，肯定就是这个 <strong>反射</strong> 啦 😄</p><p>那么，结合我们从原料中获取的重要属性之一的 beanClass ，我们可以画出这么一张图 👇</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/spring/image-20211213225124831.png" alt="image-20211213225124831"></p><p>那么我们再来看看这个 BeanFactory 叭 😄</p><h3 id="beanfactory" tabindex="-1">BeanFactory <a class="header-anchor" href="#beanfactory" aria-label="Permalink to &quot;BeanFactory&quot;">​</a></h3><p>先来看看 作为 IOC 容器的<strong>根接口</strong> 的 BeanFactory 提供了什么方法吧 👇</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/spring/image-20210904162844126.png" alt="image-20210904162844126"></p><p>主要是这个 getBean 方法，以及 <strong>别名获取</strong>，<strong>类型获取</strong> 方法和其他一些判断方法如 ：<strong>单例</strong>，<strong>多例</strong>，<strong>类型匹配</strong>，<strong>包含 bean</strong></p><p>我们来简单看看它的子接口都有哪些叭~😄</p><p>这里分享个小技巧叭 🐖</p><p>看源码的时候，一般就直接看这个<strong>默认</strong>接口 如这里的 DefaultListableBeanFactory</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/spring/image-20210904161436139.png" alt="image-20210904161436139"></p><p>基本上看个类名就知道大概作用了，那么先对号入座下 👇</p><p><strong>ListableBeanFactory</strong></p><blockquote><p>👉 遍历 bean</p></blockquote><p><strong>HierarchicalBeanFactory</strong></p><blockquote><p>👉 提供 父子关系，可以获取上一级的 BeanFactory</p></blockquote><p><strong>ConfigurableBeanFactory</strong></p><blockquote><p>👉 实现了 SingletonBeanRegistry ，主要是 单例 Bean 的注册，生成</p></blockquote><p><strong>AutowireCapableBeanFactory</strong></p><blockquote><p>👉 和自动装配有关的</p></blockquote><p><strong>AbstractBeanFactory</strong></p><blockquote><p>👉 单例缓存，以及 FactoryBean 相关的</p></blockquote><p><strong>ConfigurableListableBeanFactory</strong></p><blockquote><p>👉 预实例化单例 Bean，分析，修改 BeanDefinition</p></blockquote><p><strong>AbstractAutowireCapableBeanFactory</strong></p><blockquote><p>👉 创建 Bean ，属性注入，实例化，调用初始化方法 等等</p></blockquote><p><strong>DefaultListableBeanFactory</strong></p><blockquote><p>👉 支持单例 Bean ，Bean 别名 ，父子 BeanFactory，Bean 类型转化 ，Bean 后置处理，FactoryBean，自动装配等</p></blockquote><p>是不是非常丰富 😄</p><h3 id="factorybean" tabindex="-1">FactoryBean <a class="header-anchor" href="#factorybean" aria-label="Permalink to &quot;FactoryBean&quot;">​</a></h3><p>FactoryBean ，它本身就是个 Bean，算是小工厂 ，归 BeanFactory 这个大工厂管理的。</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/spring/image-20210904174616712.png" alt="image-20210904174616712"></p><p>可以看到它就只有三个方法</p><ol><li><code>getObject()</code> 获取对象</li><li><code>isSingleton()</code> 单例对象</li><li><code>getObjectType()</code> 返回的是 Bean 对象的类型</li></ol><p>相比大工厂 BeanFactory 少了特别多东西，没有严格的 Bean 生命周期流程 😄</p><p>FactoryBean 对象本身也是一个 Bean，是一个小工厂，可以生产另外的 Bean</p><p>BeanFactory 是 Spring 容器的根接口，是大工厂，生产各种各样的 Bean</p><p>beanName 就是正常对象</p><p>“&amp;”+beanName ， 获取的是实现了该接口的 FactoryBean 工厂对象</p><p>大致如下 👇</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/spring/image-20211213225330193.png" alt="image-20211213225330193"></p><h3 id="applicationcontext" tabindex="-1">ApplicationContext <a class="header-anchor" href="#applicationcontext" aria-label="Permalink to &quot;ApplicationContext&quot;">​</a></h3><p>我们再来看看这个 ApplicationContext</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/spring/image-20210904161808341.png" alt="image-20210904161808341"></p><p>可以看到它扩展了很多功能，除了 BeanFactory ，它还可以<strong>创建 , 获取 Bean</strong>，以及处理<strong>国际化</strong>，<strong>事件</strong>，<strong>获取资源</strong>等</p><ul><li>EnvironmentCapable 获取 环境变量 的功能，可以获取到 <strong>操作系统变量</strong> 和 <strong>JVM 环境变量</strong></li><li>ListableBeanFactory 获取所有 BeanNames，判断某个 BeanName 是否存在 BeanDefinition 对象，统计 BeanDefinition 对象，获取某个类型对应的所有 beanNames 等功能</li><li>HierarchicalBeanFactory 获取父 BeanFactory ，判断某个 name 是否存在 bean 对象的功能</li><li>MessageSource <strong>国际化功能</strong>，获取某个国际化资源</li><li>ApplicationEventPublisher <strong>事件发布功能</strong>（重点）</li><li>ResourcePatternResolver <strong>加载，获取资源的功能</strong>，这里的资源可能是文件，图片 等某个 URL 资源都可以</li></ul><p>还有这三个重要的类 👇,就不一一介绍先啦 😄</p><ol><li>ClassPathXmlApplicationContext</li><li>AnnotationConfigApplicationContext</li><li>FileSystemXmlApplicationContext</li></ol><p>赶紧来看看这个核心叭！</p><h3 id="ioc-容器" tabindex="-1">IOC 容器 <a class="header-anchor" href="#ioc-容器" aria-label="Permalink to &quot;IOC 容器&quot;">​</a></h3><p>当然，这时候出场的肯定是 IOC 啦。</p><p>我们都知道 IOC 是 <strong>控制反转</strong> ，但是别忘了 <strong>容器</strong> 这个词，比如 <strong>容器的根接口</strong> BeanFactory ，<strong>容器的实现</strong> 👇</p><ol><li>ClassPathXmlApplicationContext</li><li>AnnotationConfigApplicationContext</li><li>FileSystemXmlApplicationContext</li></ol><p>同时我们要注意这里无处不在的 <strong>后置处理器</strong> xxxPostProcessor 🐷</p><p>这个是 Spring 中扩展性强的原因了！</p><p>我们可以在各个过程中合理应用这些 PostProcessor 来扩展，或者修改 Bean 定义信息等等</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/spring/image-20211213225748030.png" alt="image-20211213225748030"></p><p>可以看到在这个容器中，完成了 Bean 的初始化，而这个过程还有很多细节 ，请往下看看 👇</p><p>DI 到时写 <strong>属性填充</strong> 时再介绍 🐷</p><h3 id="beanfactory-后置处理器" tabindex="-1">BeanFactory 后置处理器 <a class="header-anchor" href="#beanfactory-后置处理器" aria-label="Permalink to &quot;BeanFactory 后置处理器&quot;">​</a></h3><p>作为 IOC 容器根接口的 BeanFactory ，有着非常高的扩展性，比如最开始获取原料 BeanDefinition 时，就出现了两个针对 BeanFactory 工厂的后置处理器 👇</p><p>BeanDefinitionRegistryPostProcessor</p><blockquote><p>通过该接口，我们可以自己掌控我们的 <strong>原料</strong>，通过 BeanDefinitionRegistry 接口去 <strong>新增</strong>，<strong>删除</strong>，<strong>获取</strong>我们这个 BeanDefinition</p></blockquote><p>BeanFactoryPostProcessor</p><blockquote><p>通过该接口，可以在 <strong>实例化对象前</strong>，对 BeanDefinition 进行修改 ，<strong>冻结</strong> ，<strong>预实例化单例 Bean</strong> 等</p></blockquote><p>经过上面层层阻碍后，我们最终会来到目标方法 getBean ，将原料投入生产，最终获取一个个 Bean 对象出来</p><p>那么随之而来的就是这个 Bean 的生命周期啦 😄</p><h3 id="bean-生命周期" tabindex="-1">Bean 生命周期 <a class="header-anchor" href="#bean-生命周期" aria-label="Permalink to &quot;Bean 生命周期&quot;">​</a></h3><p>Bean 的创建和管理有<strong>标准化的流程</strong>！</p><p>这里在我们的工厂 BeanFactory 中写得很清楚 👇</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/spring/image-20210902072224002.png" alt="image-20210902072224002"></p><p>总共 <strong>14</strong> 个步骤，是不是一下子就清晰多了 😄</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/spring/image-20211213225831583.png" alt="image-20211213225831583"></p><p>在看这部分的源码时，要多注意两个英文单词 😝</p><ol><li><strong>实例化</strong> 👉 <strong>Instantiation</strong></li><li><strong>初始化</strong> 👉 <strong>Initialization</strong></li></ol><p>ps: 别看快搞错了 哈哈 😝</p><p>仔细阅读上面这 14 个步骤，会发现前面 <strong>8</strong> 个都是 Aware 接口，而他们的作用也很简单，就是获取 xxAware 这个单词的前缀 xx 😄</p><p>比如事件发布器 ApplicationEventPublisher ，只要你实现了 ApplicationEventPublisherAware 接口，就可以<strong>获取</strong> 事件发布器 ApplicationEventPublisher ！</p><h3 id="bean-后置处理器" tabindex="-1">Bean 后置处理器 <a class="header-anchor" href="#bean-后置处理器" aria-label="Permalink to &quot;Bean 后置处理器&quot;">​</a></h3><p>在实例化 和 初始化流程中，把这个 Bean 的后置处理器 BeanPostProcessor 安排上，就得到下图啦 👇</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/spring/image-20211213225953964.png" alt="image-20211213225953964"></p><p>这里留意下 <strong>实例化</strong> 有扩展点 InstantiationAwareBeanPostProcessor ， <strong>初始化</strong> 扩展点 BeanPostProcessor 就非常多啦，我们主要来关注下这个 AOP</p><h3 id="aop" tabindex="-1">AOP <a class="header-anchor" href="#aop" aria-label="Permalink to &quot;AOP&quot;">​</a></h3><p>那么 AOP 是在哪个步骤代理对象的呢？👇</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/spring/image-20211213230042502.png" alt="image-20211213230042502"></p><p>可以在 AbstractAutoProxyCreator 类中看到 👇</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/spring/image-20210903080803199.png" alt="image-20210903080803199"></p><h3 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h3><p>本文就先介绍到这里啦 🐖</p><p>主要介绍了 Spring 里面的这些脉络，方便小伙伴们对它有个整体的印象先~</p><p>再介绍其中的一些扩展点，比如从源材料开始的 BeanFactoryPostprocessor ，到产物 Bean 的 BeanPostprocessor 。</p><p>实例化，初始化的顺序，Bean 的生命周期，以及 BeanFactory 及子类扩展的功能，再到 ApplicationContext 的功能。</p><p>还有这个核心机制： <strong>工厂+XML+反射</strong>，以及 AOP <strong>发生的地方</strong>。😋</p><p><img src="https://fastly.jsdelivr.net/gh/doocs/source-code-hunter@main/images/spring/image-20211213230212297.png" alt="image-20211213230212297"></p>',98))])}const f=r(l,[["render",c]]);export{y as __pageData,f as default};
